import requests
import json
import time
import re
import os
from datetime import datetime

API_BASE = 'http://localhost:5000'
BATCH_SIZE = 50
HEADERS = {'User-Agent': 'DC Hub Discovery Bot/2.0 (dchub.com)'}

def submit_batch(facilities):
    if not facilities:
        return {'added': 0, 'skipped': 0}
    try:
        admin_key = os.environ.get('DCHUB_ADMIN_KEY', '')
        resp = requests.post(f'{API_BASE}/api/facilities/bulk-import',
                           json={'facilities': facilities},
                           headers={'X-Admin-Key': admin_key},
                           timeout=60)
        if resp.status_code == 200:
            return resp.json()
        return {'added': 0, 'skipped': 0}
    except:
        return {'added': 0, 'skipped': 0}

def submit_all(facilities, label=""):
    total_added = 0
    total_skipped = 0
    for i in range(0, len(facilities), BATCH_SIZE):
        batch = facilities[i:i+BATCH_SIZE]
        result = submit_batch(batch)
        total_added += result.get('added', 0)
        total_skipped += result.get('skipped', 0)
        time.sleep(0.3)
    print(f"  {label}: {total_added} added, {total_skipped} duplicates (from {len(facilities)} total)")
    return total_added

