def set_provider(facilities, provider):
    for f in facilities:
        if 'provider' not in f:
            f['provider'] = provider
        f['source'] = 'provider_directory'
        f['source_id'] = f"pd_{f['name'][:40].replace(' ','_')}"
        f['status'] = f.get('status', 'Operational')
    return facilities

def run_all():
    print("=" * 60)
    print("DC Hub Nexus - Provider Directory Scraper v2.0")
    print(f"Started at: {datetime.now().isoformat()}")
    print("=" * 60)

    grand_total = 0

    print("\n--- Equinix Global ---")
    grand_total += submit_all(set_provider(EQUINIX_DCS, "Equinix"), "Equinix")

    print("\n--- Digital Realty Global ---")
    grand_total += submit_all(set_provider(DIGITAL_REALTY_DCS, "Digital Realty"), "Digital Realty")

